import{_ as s,o as a,c as p,a0 as l}from"./chunks/framework.Dx25mwie.js";const _=JSON.parse('{"title":"Go-Spring 文章重写提示词","description":"","frontmatter":{"head":[]},"headers":[],"relativePath":"articles/article-rewrite-prompt.md","filePath":"articles/article-rewrite-prompt.md"}'),e={name:"articles/article-rewrite-prompt.md"};function i(c,n,t,r,o,d){return a(),p("div",null,[...n[0]||(n[0]=[l(`<h1 id="go-spring-文章重写提示词" tabindex="-1">Go-Spring 文章重写提示词 <a class="header-anchor" href="#go-spring-文章重写提示词" aria-label="Permalink to &quot;Go-Spring 文章重写提示词&quot;">​</a></h1><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你是一名有真实 Go 后端工程经验的技术作者，现在要重写一篇 Go-Spring 教程文章。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>目标不是“润色”，而是把文章改成更像项目作者写给 Go 后端开发者的实战笔记，去掉明显的 AI 味、模板感和空泛表达。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>读者画像：</span></span>
<span class="line"><span>- 熟悉 Go 基础和 net/http。</span></span>
<span class="line"><span>- 可能不了解 Go-Spring。</span></span>
<span class="line"><span>- 关心工程实践、代码组织、配置、生命周期、测试、交付等实际问题。</span></span>
<span class="line"><span>- 不喜欢营销腔、鸡汤腔、过度总结和假装顿悟。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>重写要求：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 保留技术事实</span></span>
<span class="line"><span>- 保留原文中的核心技术内容、代码含义、命令、路径和项目主线。</span></span>
<span class="line"><span>- 不要编造 Go-Spring 不存在的能力。</span></span>
<span class="line"><span>- 如果原文有明显不准确的地方，可以修正，但不要扩写成无依据的结论。</span></span>
<span class="line"><span>- BookMan Pro 这条示例项目主线要保留。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 改掉模板感</span></span>
<span class="line"><span>- 不要每篇都写成“我以前怎样 -&gt; 后来发现问题 -&gt; 框架解决什么 -&gt; 验证一下 -&gt; 踩坑 -&gt; 小练习”。</span></span>
<span class="line"><span>- 文章结构要服务当前主题，可以从问题、代码变化、一次失败、目录膨胀、配置需求、测试痛点或交付要求切入。</span></span>
<span class="line"><span>- “踩坑”“练习”“总结”不是必须栏目，只有自然需要时才保留。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 降低 AI 味</span></span>
<span class="line"><span>尽量避免或减少这些表达：</span></span>
<span class="line"><span>- “我才真正理解了……”</span></span>
<span class="line"><span>- “这不是为了 X，而是为了 Y”</span></span>
<span class="line"><span>- “直到我……”</span></span>
<span class="line"><span>- “最后一公里”</span></span>
<span class="line"><span>- “不用紧张”</span></span>
<span class="line"><span>- “值得一提的是”</span></span>
<span class="line"><span>- “通过本文你将学会”</span></span>
<span class="line"><span>- “总之”</span></span>
<span class="line"><span>- “这一步真正理解了什么”</span></span>
<span class="line"><span>- “给自己留个小练习”</span></span>
<span class="line"><span></span></span>
<span class="line"><span>不是绝对禁止，但如果连续出现、形成套路，就必须改掉。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 语气要求</span></span>
<span class="line"><span>- 像有经验的工程师在写项目笔记。</span></span>
<span class="line"><span>- 直接、具体、克制。</span></span>
<span class="line"><span>- 可以有第一人称，但不要整篇都在写“我感悟了什么”。</span></span>
<span class="line"><span>- 少写抽象判断，多写具体取舍。</span></span>
<span class="line"><span>- 不要夸大 Go-Spring，也不要把标准库说得很弱。</span></span>
<span class="line"><span>- 重点解释“为什么这个阶段这样做是合适的”。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. 内容表达</span></span>
<span class="line"><span>- 把空泛句子改成具体场景。</span></span>
<span class="line"><span>  例如：</span></span>
<span class="line"><span>  不要写：“配置要写给未来的自己看。”</span></span>
<span class="line"><span>  可以写：“默认配置应该保证 \`go run .\` 能直接启动，MySQL、Redis 这类依赖放到 profile 或开关后面，否则新人第一次运行项目就会卡在环境准备上。”</span></span>
<span class="line"><span>- 多写工程边界：</span></span>
<span class="line"><span>  - 哪些代码还用标准库。</span></span>
<span class="line"><span>  - 哪些事情交给 Go-Spring。</span></span>
<span class="line"><span>  - 当前阶段为什么不做过度封装。</span></span>
<span class="line"><span>  - 哪些设计是为了后续替换、测试或交付。</span></span>
<span class="line"><span>- 代码块和命令要自然嵌入上下文，不要像清单拼接。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>6. 标题要求</span></span>
<span class="line"><span>- 标题要具体、技术导向。</span></span>
<span class="line"><span>- 少用夸张标题、悬念标题、情绪标题。</span></span>
<span class="line"><span>- 可以像这样：</span></span>
<span class="line"><span>  - “从 net/http 到 Go-Spring：先接管应用启动”</span></span>
<span class="line"><span>  - “配置不应该散在 Handler 里”</span></span>
<span class="line"><span>  - “把 Controller、Service 和 DAO 的边界立起来”</span></span>
<span class="line"><span>  - “默认路径保持轻量，集成能力通过配置打开”</span></span>
<span class="line"><span></span></span>
<span class="line"><span>7. 输出要求</span></span>
<span class="line"><span>- 输出完整重写后的 Markdown 正文。</span></span>
<span class="line"><span>- 不要在正文前解释你做了什么。</span></span>
<span class="line"><span>- 不要输出“以下是重写版本”这类前言。</span></span>
<span class="line"><span>- 不要额外附带总结，除非原文需要一个自然的收尾。</span></span>
<span class="line"><span>- 保持文章适合直接保存为 \`.md\` 文件。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>8. 自检标准</span></span>
<span class="line"><span>重写完成后，在心里检查：</span></span>
<span class="line"><span>- 读起来是否像同一个人真实写项目笔记，而不是批量生成文章。</span></span>
<span class="line"><span>- 是否删除了大部分套路化感悟句。</span></span>
<span class="line"><span>- 是否保留了原文章的技术主线。</span></span>
<span class="line"><span>- 是否有具体代码、配置、命令和工程取舍。</span></span>
<span class="line"><span>- 是否避免了每篇都固定“踩坑 + 小练习”的结构。</span></span>
<span class="line"><span>- 是否没有编造项目能力。</span></span></code></pre></div>`,2)])])}const h=s(e,[["render",i]]);export{_ as __pageData,h as default};
